const tests = await fetch(code + '/_api/get-tests');
const parsed = await tests.json();
assert.isTrue(parsed.length >= 10);
parsed.forEach((test) => {
  assert.equal(test.state, 'passed');
  assert.isAtLeast(test.assertions.length, 1);
});
